SELECT education_name
FROM educations
WHERE degree_type = 'Bachelor''s';

SELECT workclass_name
FROM workclasses
WHERE workclass_id = 1;

SELECT education_name
FROM educations
WHERE education_num = (SELECT MAX(education_num) FROM educations);

SELECT relationship_name
FROM relationships
WHERE relationship_name = 'Divorced';

SELECT education_name
FROM educations
ORDER BY education_name ASC;

SELECT AVG(e.education_num) AS average_education_num
FROM educations e
WHERE e.education_name = 'Bachelors';

SELECT occupation_name
FROM occupations
WHERE industry = 'Finance';
